private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
  this.logger.info(
    `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
  );

  const recipient = event.user?.email ?? event.order.userId;
  const userId = event.user?.id ?? event.order.userId;

  const basePayload = {
    recipient,
    subject: `Order Update: ${event.order.id}`,
    body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    type: 'order_status_update' as const,
    priority: 'normal' as const,
  };

  // Send to each registered channel, checking per-channel preferences
  for (const [channel] of this.adapters) {
    if (this.preferencesService && !this.preferencesService.shouldSendToChannel(userId, channel, 'order_status_update')) {
      this.logger.info(`Skipping status update on ${channel} for user ${userId} — disabled by preferences`);
      continue;
    }

    await this.sendNotification({
      ...basePayload,
      channel,
    });
  }

  // Fallback: if no adapters registered, still store notification (backward compat)
  if (this.adapters.size === 0) {
    if (this.preferencesService && !this.preferencesService.shouldSendToChannel(userId, 'email', 'order_status_update')) {
      this.logger.info(`Skipping status update for user ${userId} — disabled by preferences`);
      return;
    }

    await this.sendNotification({
      ...basePayload,
      channel: 'email',
    });
  }
}

